async (params, browser) => {
  // Open page
  await browser.open('https://app.todoist.com/app/today')

  // Wait for content
  await browser.waitForSelector('.task_list_item, [data-testid="task"]', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const tasks = Array.from(document.querySelectorAll('.task_list_item, [data-testid="task"]')).slice(0,50).map(el => { const title = el.querySelector('.task_content, [data-testid="task-name"]')?.textContent?.trim()||''; const project = el.querySelector('[class*="project"], .project_link')?.textContent?.trim()||''; const priority = el.querySelector('[class*="priority"]')?.className?.match(/priority_(\d)/)?.[1]||''; return { title, project, priority }; }).filter(t=>t.title); return { view: 'Today', tasks }`)

  return page_data
}
